import os
from cryptography.hazmat.primitives import padding
from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.backends import default_backend
from cryptography.exceptions import InvalidPadding
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2HMAC

def generate_key(password):
    salt = os.urandom(16)
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100000,
        backend=default_backend()
    )
    key = kdf.derive(password.encode())
    return key, salt

def encrypt_credit_card(card_number):
    password = os.environ['ENCRYPTION_PASSWORD']
    key, salt = generate_key(password)
    
    # Generate a random 128-bit IV.
    iv = os.urandom(16)
    
    # Create a new AES-CBC cipher object with the given key and IV.
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    
    # Encrypt the plaintext.
    encryptor = cipher.encryptor()
    padder = padding.PKCS7(128).padder()
    padded_data = padder.update(card_number.encode()) + padder.finalize()
    ct = encryptor.update(padded_data) + encryptor.finalize()
    
    return iv + ct

def decrypt_credit_card(ct):
    password = os.environ['ENCRYPTION_PASSWORD']
    key, salt = generate_key(password)
    
    # Extract the IV from the ciphertext.
    iv = ct[:16]
    ct = ct[16:]
    
    # Create a new AES-CBC cipher object with the given key and IV.
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    
    # Decrypt the ciphertext.
    decryptor = cipher.decryptor()
    try:
        pt = decryptor.update(ct) + decryptor.finalize()
    except InvalidPadding:
        return None
    
    # Unpad the decrypted data.
    unpadder = padding.PKCS7(128).unpadder()
    try:
        card_number = unpadder.update(pt) + unpadder.finalize()
    except InvalidPadding:
        return None
    
    return card_number.decode()

